document.addEventListener("DOMContentLoaded", function () {
  gsap.registerPlugin(ScrollTrigger);

  gsap.to(".logo", {
    y: "-50%",
    scale: 0.35,
    ease: "none",
    scrollTrigger: {
      trigger: ".dashboard",
      start: "top top",
      end: "100vh top",
      scrub: 1,
    },
  });

  gsap.to(".dashboard", {
    y: "-25%",
    ease: "none",
    scrollTrigger: {
      trigger: ".dashboard",
      start: "top top",
      end: "200vh top",
      scrub: 1,
    },
  });

  gsap.to("#dashboard-img", {
    filter: "blur(10px)",
    ease: "none",
    scrollTrigger: {
      trigger: ".dashboard",
      start: "600vh top",
      end: "1000vh top",
      scrub: 0.5,
    },
  });

  gsap.to("#window img", {
    opacity: 0,
    ease: "none",
    scrollTrigger: {
      trigger: ".dashboard",
      start: "400vh top",
      end: "450vh top",
      scrub: 0.5,
    },
  });

  gsap.to(".dashboard", {
    transformOrigin: "center 85.6%",
    scale: 75,
    ease: "none",
    scrollTrigger: {
      trigger: ".dashboard",
      start: "600vh top",
      end: "900vh top",
      scrub: 1,
    },
  });

  gsap.to(".dashboard", {
    opacity: 0,
    display: "none",
    ease: "none",
    scrollTrigger: {
      trigger: ".dashboard",
      start: "800vh top",
      end: "825vh top",
      scrub: true,
    },
  });
});

code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: "PP Neue Montreal";
  background: rgb(215, 176, 138);
  background: linear-gradient(
    7deg,
    rgba(215, 176, 138, 1) 0%,
    rgba(37, 80, 156, 1) 100%
  );
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

i {
  font-size: 20px;
}

.logo {
  position: fixed;
  width: 300px;
  top: 25%;
  left: 50%;
  transform: translate(-50%, -50%);
  z-index: 2;
}

.container {
  width: 100%;
  height: 100%;
}

.dashboard {
  position: fixed;
  top: 0;
  width: 100%;
  height: 150vh;
  z-index: 1;
}

.dock {
  position: absolute;
  width: 25%;
  left: 50%;
  transform: translate(-50%, -50%);
  bottom: 11.5%;
  height: 50px;
  border-radius: 10px;
  overflow: hidden;
  display: flex;
  padding: 4px;
}

.dock > div {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
  background: #e8ebee;
  border: 16px solid #e8ebee;
  margin: -0.5px;
}

.icon:nth-child(1) {
  border-radius: 8px 0 0 8px;
}

.icon:nth-child(5) {
  border-radius: 0 8px 8px 0;
}

.icon#window {
  background: transparent !important;
  border: 4px solid #e8ebee !important;
}

.whitespace {
  width: 100%;
  height: 175vh;
}

.copy {
  width: 70%;
  margin: 0 auto;
}

h1 {
  font-size: 5vw;
  font-weight: 500;
  line-height: 120%;
  text-align: center;
  color: rgba(255, 255, 255, 0.5);
  margin-bottom: 4em;
}

h1 span {
  color: #fff;
}

@media (max-width: 900px) {
  .dock {
    width: 75%;
  }
}
